import React from 'react';
import { formatDate } from '../data/bookingData.js';
import styles from '../styles/BookingSummary.module.css';

// Pricing from soft-opening rates
const RATES = {
  dayUse: {
    label: 'Day Use',
    hours: '8:00 AM – 8:00 PM',
    weekday: 8000,
    weekend: 10000,
  },
  overnight: {
    label: 'Overnight',
    hours: '2:00 PM – 11:00 AM',
    weekday: 10000,
    weekend: 13000,
  },
};

const INCLUDED_GUESTS = 15;
const EXTRA_GUEST_FEE = 250;
const MAX_EXTRA_GUESTS = 15;

// Returns true if a Date falls on Friday, Saturday, or Sunday
function isWeekend(date) {
  const day = new Date(date).getDay(); // 0=Sun,5=Fri,6=Sat
  return day === 0 || day === 5 || day === 6;
}

export function calcBookingTotal(bookingType, checkIn, guests) {
  if (!bookingType || !checkIn) return { base: 0, extraGuestFee: 0, total: 0 };
  const rate = RATES[bookingType];
  const base = isWeekend(checkIn) ? rate.weekend : rate.weekday;
  const extraGuests = Math.max(0, Math.min(guests - INCLUDED_GUESTS, MAX_EXTRA_GUESTS));
  const extraGuestFee = extraGuests * EXTRA_GUEST_FEE;
  return { base, extraGuestFee, total: base + extraGuestFee };
}

const BookingSummary = ({
  bookingType, checkIn,
  guests, guestName, guestContact, contactMethod,
  onSubmit,
}) => {
  const rate = bookingType ? RATES[bookingType] : null;
  const weekend = checkIn ? isWeekend(checkIn) : false;
  const { base, extraGuestFee, total } = calcBookingTotal(bookingType, checkIn, guests);
  const extraGuests = Math.max(0, Math.min(guests - INCLUDED_GUESTS, MAX_EXTRA_GUESTS));

  const canSubmit =
    bookingType && checkIn && guests > 0 &&
    guestName?.trim() && guestContact?.trim();

  return (
    <aside className={styles.panel}>
      <div className={styles.panelHeader}>
        <span className={styles.kanjiSmall}>予約</span>
        <h2 className={styles.panelTitle}>Booking Summary</h2>
      </div>

      <div className={styles.panelBody}>
        {!bookingType && (
          <p className={styles.hint}>Choose Day Use or Overnight to begin.</p>
        )}

        {bookingType && (
          <div className={styles.typeBlock}>
            <div className={styles.typeIcon}>
              {bookingType === 'dayUse' ? '☀️' : '🌙'}
            </div>
            <div>
              <div className={styles.typeName}>{rate.label}</div>
              <div className={styles.typeHours}>{rate.hours}</div>
            </div>
          </div>
        )}

        {checkIn && (
          <div className={styles.datesBlock}>
            <div className={styles.dateItem}>
              <span className={styles.dateLabel}>Date</span>
              <span className={styles.dateValue}>{formatDate(checkIn)}</span>
              <span className={styles.dateTime}>
                {weekend ? 'Weekend rate' : 'Weekday rate'}
              </span>
            </div>
          </div>
        )}

        {bookingType && checkIn && (
          <div className={styles.priceBlock}>
            <div className={styles.priceRow}>
              <span>{rate.label} ({weekend ? 'Weekend' : 'Weekday'})</span>
              <span>₱{base.toLocaleString()}</span>
            </div>
            {extraGuests > 0 && (
              <div className={styles.priceRow}>
                <span>Extra guests ({extraGuests} × ₱{EXTRA_GUEST_FEE})</span>
                <span>₱{extraGuestFee.toLocaleString()}</span>
              </div>
            )}
            <div className={`${styles.priceRow} ${styles.totalRow}`}>
              <span>Total</span>
              <span>₱{total.toLocaleString()}</span>
            </div>
            <p className={styles.priceNote}>
              Includes up to {INCLUDED_GUESTS} guests · VAT inclusive · Pay upon arrival
            </p>
          </div>
        )}

        {guestContact && (
          <div className={styles.contactRow}>
            <span className={styles.contactLabel}>
              {contactMethod === 'email' ? '✉ Email' : '✦ Messenger'}
            </span>
            <span className={styles.contactValue}>{guestContact}</span>
          </div>
        )}
      </div>

      <div className={styles.panelFooter}>
        <button
          className={styles.cta}
          disabled={!canSubmit}
          onClick={onSubmit}
          type="button"
        >
          <span className={styles.ctaText}>Confirm Reservation</span>
          <span className={styles.ctaArrow}>→</span>
        </button>
        {!canSubmit && (
          <p className={styles.ctaNote}>
            {!bookingType
              ? 'Choose Day Use or Overnight'
              : !checkIn
              ? 'Select a date'
              : !guestName?.trim()
              ? 'Enter your name'
              : 'Complete your details'}
          </p>
        )}
      </div>
    </aside>
  );
};

export default BookingSummary;
